const item = $input.first().json;
const os = item.order_state || {};
const slim = {};

if (os.customer_name) slim.customer_name = os.customer_name;
if (os.customer_language) slim.customer_language = os.customer_language;
if (os.existing_order_id) slim.existing_order_id = os.existing_order_id;
if (os.existing_order_status) slim.existing_order_status = os.existing_order_status;
if (os.conversation_mode) slim.conversation_mode = os.conversation_mode;
if (os.pending_action) slim.pending_action = os.pending_action;

const validPm = ['Cash', 'EFT'];
const pm = validPm.includes(os.detected_payment_method) ? os.detected_payment_method
         : validPm.includes(os.payment_method) ? os.payment_method
         : null;
if (pm) slim.payment_method = pm;

if (os.requested_quantity != null) slim.requested_quantity = os.requested_quantity;
if (os.requested_category) slim.requested_category = os.requested_category;
if (os.requested_weight_range) slim.requested_weight_range = os.requested_weight_range;
if (os.requested_sex) slim.requested_sex = os.requested_sex;
if (os.timing_preference) slim.timing_preference = os.timing_preference;
if (os.collection_location) slim.collection_location = os.collection_location;

const intents = ['quote_intent', 'order_commitment_intent', 'conversation_commitment_intent', 'cancel_order_intent', 'send_for_approval_intent', 'has_existing_draft'];
for (const key of intents) {
  if (os[key] !== undefined) slim[key] = os[key];
}

if (Array.isArray(os.requested_items) && os.requested_items.length > 0) {
  slim.requested_items_compact = os.requested_items.slice(0, 5).map(function(i) {
    return { qty: i.quantity, sex: i.sex, category: i.category, weight_range: i.weight_range };
  });
}

const sc = {};
if (item.success !== undefined) {
  sc.success = item.success;
  if (item.message) sc.message = String(item.message).slice(0, 200);
}
if (item.backend_success !== undefined) sc.backend_success = item.backend_success;
if (item.backend_error) sc.backend_error = String(item.backend_error).slice(0, 200);

const syncRes = Array.isArray(item.results) && item.results.length
  ? item.results
  : (Array.isArray(item.sync_results) && item.sync_results.length ? item.sync_results : []);

if (item.partial_fulfillment === true) sc.partial_fulfillment = true;

if (syncRes.length > 0) {
  sc.had_errors = syncRes.some(function(r) { return r.error && r.error !== ''; });
  sc.had_partial = syncRes.some(function(r) { return r.match_status === 'partial_match'; });
  if (sc.had_partial) sc.partial_fulfillment = true;

  const raw = syncRes.map(function(r) { return (r.request_item_key || '?') + ': ' + (r.match_status || '?'); }).join(', ');
  sc.summary = raw.length > 300 ? raw.slice(0, 297) + '...' : raw;

  const partialBits = [];
  for (let i = 0; i < syncRes.length; i++) {
    const r = syncRes[i];
    if (r.match_status !== 'partial_match') continue;
    const req = r.requested_quantity;
    const lined = r.matched_quantity;
    const avail = r.available_quantity;
    let altStr = '';
    if (Array.isArray(r.alternatives) && r.alternatives.length > 0) {
      altStr = r.alternatives.slice(0, 4).map(function(a) {
        const band = a.weight_band || a.sale_category || '?';
        const n = a.available_count != null ? a.available_count : '';
        return n !== '' ? (band + ' x' + n) : band;
      }).join('; ');
    }
    let chunk = 'requested=' + req + ', added_to_draft=' + lined;
    if (avail != null && avail !== '') chunk += ', matched_in_requested_band=' + avail;
    if (altStr) chunk += '; other_bands_same_category=' + altStr;
    partialBits.push(chunk);
  }
  if (partialBits.length > 0) {
    sc.partial_stock_detail = partialBits.join(' | ').slice(0, 450);
  }
}

const out = Object.assign({}, item, { sam_order_state_slim: slim });
if (Object.keys(sc).length > 0) out.sam_steward_result_compact = sc;

return [{ json: out }];

